code.C:
#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int U, V;
        scanf("%d %d", &U, &V);
        printf("%lld\n", (long long)(U + V) * (U + V + 1) / 2);
    }
    return 0;
}

