import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int U = sc.nextInt();
            int V = sc.nextInt();
            System.out.println((long)(U + V) * (U + V + 1) / 2);
        }
    }
}

